import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchAdminRfqs, respondToRfq } from "../../features/b2b/adminB2bSlice";
import { toast } from "react-toastify";
import { Link } from "react-router-dom";
import {
  FileText, Clock, CheckCircle2, XCircle, ArrowLeft,
  Search, ChevronDown, Loader2, Send, MessageSquare
} from "lucide-react";

const rfqStatusConfig = {
  SUBMITTED: { label: "Submitted", color: "bg-amber-50 text-amber-700 border-amber-200", icon: Clock },
  QUOTED: { label: "Quoted", color: "bg-indigo-50 text-indigo-700 border-indigo-200", icon: MessageSquare },
  ACCEPTED: { label: "Accepted", color: "bg-emerald-50 text-emerald-700 border-emerald-200", icon: CheckCircle2 },
  REJECTED: { label: "Rejected", color: "bg-rose-50 text-rose-700 border-rose-200", icon: XCircle },
  EXPIRED: { label: "Expired", color: "bg-slate-100 text-slate-600 border-slate-200", icon: Clock },
};

const AdminB2bRfqs = () => {
  const dispatch = useDispatch();
  const { rfqs, rfqsMeta, isLoading } = useSelector((s) => s.adminB2b);

  const [statusFilter, setStatusFilter] = useState("");
  const [page, setPage] = useState(1);
  const [expandedId, setExpandedId] = useState(null);
  const [quoteForm, setQuoteForm] = useState({ totalQuotedPrice: "", validUntil: "", responseNotes: "" });

  const fetchRfqs = () => {
    const params = { page, limit: 20 };
    if (statusFilter) params.status = statusFilter;
    dispatch(fetchAdminRfqs(params));
  };

  useEffect(() => { fetchRfqs(); }, [statusFilter, page]);

  const handleRespond = async (id) => {
    if (!quoteForm.totalQuotedPrice) {
      toast.error("Enter a quoted price");
      return;
    }
    try {
      await dispatch(respondToRfq({
        id,
        totalQuotedPrice: parseFloat(quoteForm.totalQuotedPrice),
        validUntil: quoteForm.validUntil || undefined,
        responseNotes: quoteForm.responseNotes || undefined,
      })).unwrap();
      toast.success("Quote sent to customer!");
      setQuoteForm({ totalQuotedPrice: "", validUntil: "", responseNotes: "" });
      setExpandedId(null);
      fetchRfqs();
    } catch (err) { toast.error(err || "Response failed"); }
  };

  return (
    <div className="min-h-screen bg-[#f8fafc]">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-8">
          <Link to="/admin" className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-indigo-600 mb-2">
            <ArrowLeft size={16} /> Admin Dashboard
          </Link>
          <h1 className="text-2xl font-black text-slate-900">B2B Requests For Quotes</h1>
          <p className="text-sm text-slate-500 font-medium mt-1">
            Review and respond to bulk procurement quote requests
          </p>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-3xl border border-slate-100 p-5 mb-6 shadow-sm flex flex-col sm:flex-row gap-4">
          <select
            value={statusFilter}
            onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
            className="h-10 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-600"
          >
            <option value="">All RFQ Statuses</option>
            {Object.entries(rfqStatusConfig).map(([key, { label }]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>

        {/* RFQ List */}
        {isLoading ? (
          <div className="flex items-center justify-center py-24">
            <Loader2 size={32} className="text-indigo-600 animate-spin" />
          </div>
        ) : rfqs?.length > 0 ? (
          <div className="flex flex-col gap-4">
            {rfqs.map((rfq) => {
              const cfg = rfqStatusConfig[rfq.status] || rfqStatusConfig.SUBMITTED;
              const StatusIcon = cfg.icon;
              const isExpanded = expandedId === rfq.id;
              const date = rfq.createdAt ? new Date(rfq.createdAt).toLocaleDateString("en-US", {
                year: "numeric", month: "short", day: "numeric",
              }) : "—";

              return (
                <div key={rfq.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                  <div
                    className="p-5 flex flex-col sm:flex-row sm:items-center gap-4 cursor-pointer hover:bg-slate-50/50"
                    onClick={() => setExpandedId(isExpanded ? null : rfq.id)}
                  >
                    <div className="flex items-center gap-3 sm:w-44 flex-shrink-0">
                      <div className={`w-9 h-9 rounded-xl flex items-center justify-center border ${cfg.color}`}>
                        <StatusIcon size={16} />
                      </div>
                      <div>
                        <span className={`text-[9px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded border ${cfg.color}`}>
                          {cfg.label}
                        </span>
                        <p className="text-[10px] text-slate-400 font-medium mt-0.5">{date}</p>
                      </div>
                    </div>

                    <div className="flex-1 min-w-0">
                      <span className="font-extrabold text-slate-900 text-sm block">
                        {rfq.rfqNumber || `RFQ-${rfq.id?.slice(0, 8)}`}
                      </span>
                      <span className="text-[10px] text-slate-400 font-bold">
                        {rfq.user?.institutionName || rfq.user?.email || "—"} • {rfq.items?.length || 0} items
                      </span>
                    </div>

                    <div className="flex items-center gap-3 flex-shrink-0">
                      {rfq.totalQuotedPrice && (
                        <span className="text-sm font-black text-indigo-600">
                          {parseFloat(rfq.totalQuotedPrice).toLocaleString()} ETB
                        </span>
                      )}
                      <ChevronDown size={16} className={`text-slate-400 transition-transform ${isExpanded ? "rotate-180" : ""}`} />
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="border-t border-slate-100 p-5 bg-slate-50/50 space-y-4">
                      {/* Items */}
                      {rfq.items?.length > 0 && (
                        <div>
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Requested Items</h4>
                          <div className="space-y-2">
                            {rfq.items.map((item, i) => (
                              <div key={i} className="flex justify-between bg-white rounded-xl p-3 text-sm border border-slate-100">
                                <div>
                                  <span className="font-bold text-slate-800">{item.product?.title || item.genericName || "Custom Item"}</span>
                                  {item.genericName && <span className="text-[10px] text-slate-400 block italic">{item.genericName}</span>}
                                </div>
                                <span className="font-bold text-slate-600">Qty: {item.quantity || "—"}</span>
                              </div>
                            ))}
                          </div>
                        </div>
                      )}

                      {rfq.notes && (
                        <div className="bg-white rounded-xl p-3 border border-slate-100">
                          <span className="text-[10px] font-black text-slate-400 uppercase block mb-1">Customer Notes</span>
                          <p className="text-xs text-slate-600 font-medium">{rfq.notes}</p>
                        </div>
                      )}

                      {/* Quote Response Form */}
                      {rfq.status === "SUBMITTED" && (
                        <div className="bg-white rounded-2xl p-4 border border-indigo-100 space-y-3">
                          <h4 className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center gap-1.5">
                            <Send size={12} /> Send Quote Response
                          </h4>
                          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                            <input
                              type="number"
                              placeholder="Total Quoted Price (ETB)"
                              value={quoteForm.totalQuotedPrice}
                              onChange={(e) => setQuoteForm({ ...quoteForm, totalQuotedPrice: e.target.value })}
                              className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
                            />
                            <input
                              type="date"
                              placeholder="Valid Until"
                              value={quoteForm.validUntil}
                              onChange={(e) => setQuoteForm({ ...quoteForm, validUntil: e.target.value })}
                              className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none"
                            />
                            <input
                              type="text"
                              placeholder="Notes to customer..."
                              value={quoteForm.responseNotes}
                              onChange={(e) => setQuoteForm({ ...quoteForm, responseNotes: e.target.value })}
                              className="h-10 px-4 rounded-xl border border-slate-200 text-sm font-medium focus:outline-none"
                            />
                          </div>
                          <button
                            onClick={() => handleRespond(rfq.id)}
                            className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-wider hover:bg-indigo-700 transition-colors flex items-center gap-2"
                          >
                            <Send size={14} /> Send Quote
                          </button>
                        </div>
                      )}

                      {rfq.status === "QUOTED" && (
                        <div className="bg-indigo-50 rounded-2xl p-4 border border-indigo-100">
                          <span className="text-xs font-black text-indigo-600">
                            Quote sent: {parseFloat(rfq.totalQuotedPrice || 0).toLocaleString()} ETB — Awaiting customer response
                          </span>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-24 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <FileText size={48} className="text-slate-200 mb-4" />
            <p className="text-sm font-black text-slate-400 uppercase tracking-widest">No RFQs found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminB2bRfqs;
